import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Sidebar from '../components/Sidebar';
import CarCard from '../components/CarCard';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalBookings: 0,
    activeRentals: 0,
    totalSpent: 0,
    completedReturns: 0
  });
  const [recentCars, setRecentCars] = useState([]);
  const [loading, setLoading] = useState(true);

  // Mock data
  const mockCars = [
    {
      id: 1,
      name: 'Tesla Model S',
      brand: 'Tesla',
      model: 'Model S',
      year: 2024,
      pricePerDay: 150,
      category: 'Electric',
      seats: 5,
      fuelType: 'Electric',
      transmission: 'Automatic',
      available: true,
      image: 'https://via.placeholder.com/300x200?text=Tesla+Model+S'
    },
    {
      id: 2,
      name: 'BMW X5',
      brand: 'BMW',
      model: 'X5',
      year: 2023,
      pricePerDay: 120,
      category: 'SUV',
      seats: 7,
      fuelType: 'Diesel',
      transmission: 'Automatic',
      available: true,
      image: 'https://via.placeholder.com/300x200?text=BMW+X5'
    },
    {
      id: 3,
      name: 'Mercedes C-Class',
      brand: 'Mercedes',
      model: 'C-Class',
      year: 2023,
      pricePerDay: 100,
      category: 'Sedan',
      seats: 5,
      fuelType: 'Petrol',
      transmission: 'Automatic',
      available: true,
      image: 'https://via.placeholder.com/300x200?text=Mercedes+C-Class'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setStats({
        totalBookings: 12,
        activeRentals: 2,
        totalSpent: 2450,
        completedReturns: 10
      });
      setRecentCars(mockCars);
      setLoading(false);
    }, 500);
  }, []);

  const handleRentCar = (car) => {
    console.log('Rent car from dashboard:', car);
  };

  return (
    <div className="dashboard-page">
      <Sidebar />
      
      <div className="dashboard-content">
        <div className="dashboard-header">
          <h1>Dashboard</h1>
          <p>Welcome back! Here's your rental overview.</p>
        </div>

        {/* Stats Cards */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon">📅</div>
            <div className="stat-info">
              <h3>{stats.totalBookings}</h3>
              <p>Total Bookings</p>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon">🚗</div>
            <div className="stat-info">
              <h3>{stats.activeRentals}</h3>
              <p>Active Rentals</p>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon">💰</div>
            <div className="stat-info">
              <h3>₱{stats.totalSpent.toLocaleString()}</h3>
              <p>Total Spent</p>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon">✅</div>
            <div className="stat-info">
              <h3>{stats.completedReturns}</h3>
              <p>Completed Returns</p>
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="quick-actions">
          <h2>Quick Actions</h2>
          <div className="actions-grid">
            <Link to="/my-bookings" className="action-card">
              <span className="action-icon">📅</span>
              <span className="action-label">View Bookings</span>
            </Link>
            <Link to="/my-returns" className="action-card">
              <span className="action-icon">🔄</span>
              <span className="action-label">Manage Returns</span>
            </Link>
            <Link to="/payments" className="action-card">
              <span className="action-icon">💳</span>
              <span className="action-label">Payments</span>
            </Link>
            <Link to="/profile" className="action-card">
              <span className="action-icon">👤</span>
              <span className="action-label">My Profile</span>
            </Link>
          </div>
        </div>

        {/* Available Cars */}
        <div className="available-cars">
          <h2>Available Cars for Rent</h2>
          {loading ? (
            <div className="loading">Loading cars...</div>
          ) : (
            <div className="cars-grid">
              {recentCars.map(car => (
                <CarCard 
                  key={car.id} 
                  car={car} 
                  onRent={handleRentCar}
                />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
